const apiKey = $env.SAM_API_KEY;
if (!apiKey) throw new Error('SAM_API_KEY not set');

const naicsList = ($env.SAM_NAICS_CODES || '541511,541512,541519,518210,511210').split(',').map(s => s.trim()).filter(Boolean);
const ptypes = ['o','k','p','r'];

function fmt(d) {
  const m = String(d.getMonth()+1).padStart(2,'0');
  const day = String(d.getDate()).padStart(2,'0');
  const y = d.getFullYear();
  return `${m}/${day}/${y}`;
}

const end = new Date();
const start = new Date();
start.setDate(start.getDate() - 1);
const postedFrom = fmt(start);
const postedTo = fmt(end);

const all = [];

for (const ncode of naicsList) {
  for (const ptype of ptypes) {
    let offset = 0;
    while (true) {
      const qs = new URLSearchParams({
        api_key: apiKey,
        postedFrom,
        postedTo,
        ncode,
        ptype,
        limit: '1000',
        offset: String(offset),
      });
      const url = `https://api.sam.gov/opportunities/v2/search?${qs}`;
      const res = await this.helpers.httpRequest({ method: 'GET', url, json: true });
      const records = res.opportunitiesData || res.data || [];
      if (!Array.isArray(records) || records.length === 0) break;
      all.push(...records);
      if (records.length < 1000) break;
      offset += 1000;
    }
  }
}

return [{ json: { records: all, count: all.length, postedFrom, postedTo } }];

const NAICS = ['541511','541512','541519','518210','511210'];
const PSC_PREFIX = ['D3','7E'];
const KEYWORDS = ['software','application','cloud','devsecops','cybersecurity','api','modernization','saas','database','agile'];

function parseDate(v){if(!v)return null;const d=new Date(v);return isNaN(d)?null:d.toISOString().slice(0,10);}
function parseTs(v){if(!v)return null;const d=new Date(v);return isNaN(d)?null:d.toISOString();}
function passes(opp){
  if(NAICS.includes(opp.naics||''))return true;
  if(PSC_PREFIX.some(p=>(opp.psc||'').startsWith(p)))return true;
  const t=(opp.title||'').toLowerCase();
  return KEYWORDS.some(k=>t.includes(k));
}

const records = $input.first().json.records || [];
const out = [];
const seen = new Set();

for (const rec of records) {
  const noticeId = rec.noticeId || rec.noticeid;
  if (!noticeId || seen.has(noticeId)) continue;
  seen.add(noticeId);
  const pop = rec.placeOfPerformance || {};
  const opp = {
    notice_id: noticeId,
    source: 'federal:sam',
    solicitation_number: rec.solicitationNumber || null,
    title: rec.title || null,
    posted_date: parseDate(rec.postedDate),
    response_deadline: parseTs(rec.responseDeadLine || rec.responseDeadline),
    naics: rec.naicsCode || rec.naics || null,
    psc: rec.classificationCode || null,
    set_aside: rec.setAside || null,
    set_aside_code: rec.setAsideCode || null,
    procurement_type: rec.type || rec.ptype || null,
    agency: rec.fullParentPathName || rec.department || null,
    office: typeof rec.officeAddress === 'string' ? rec.officeAddress : null,
    place_of_performance: [pop.city, pop.state, pop.zip].filter(Boolean).join(', ') || null,
    state_code: pop.state || null,
    ui_link: rec.uiLink || null,
    description_url: rec.description || null,
    active: true,
    raw_data: rec,
  };
  if (!passes(opp)) continue;
  out.push({ json: opp });
}
return out;
